    assert solution.threeSum([1, -1]) == []

def test_threeSum_no_triplets():
    solution = Solution()
    assert solution.threeSum([1, 2, 3]) == []

def test_threeSum_single_triplet():
    solution = Solution()
    assert solution.threeSum([-1, 0, 1]) == [(-1, 0, 1)]

def test_threeSum_multiple_triplets():
    solution = Solution()
    assert solution.threeSum([-1, 0, 1, 2, -1, -4]) == [(-1, -1, 2), (-1, 0, 1)]

def test_threeSum_duplicate_triplets():
